<section class="page-heading split"><div><span class="eyebrow blue">Organização dos treinamentos</span><h1>Categorias de sistemas</h1><p>Cadastre os sistemas que compõem os veículos e facilitam a localização dos conteúdos.</p></div><?php if(can('categories','create')): ?><button class="btn primary" data-category-create><i class="bi bi-plus-lg"></i> Nova categoria</button><?php endif; ?></section>
<?php if($flash): ?><div class="alert <?= $flash['type']==='success'?'success':'error' ?>"><i class="bi <?= $flash['type']==='success'?'bi-check-circle':'bi-exclamation-circle' ?>"></i> <?= e($flash['message']) ?></div><?php endif; ?>
<section class="panel">
<form class="panel-head table-filters" method="get" action="<?= url('categorias') ?>"><div class="search"><span><i class="bi bi-search"></i></span><input type="search" name="q" value="<?= e($q) ?>" placeholder="Buscar sistema ou descrição..."></div><div class="panel-filters"><select name="status"><option value="">Todas as situações</option><option value="ativo" <?= $status==='ativo'?'selected':'' ?>>Ativas</option><option value="inativo" <?= $status==='inativo'?'selected':'' ?>>Inativas</option></select><button class="btn secondary"><i class="bi bi-search"></i> Buscar</button><?php if($q!==''||$status!==''): ?><a class="btn secondary" href="<?= url('categorias') ?>" aria-label="Limpar filtros"><i class="bi bi-x-lg"></i></a><?php endif; ?></div></form>
<div class="table-wrap"><table><thead><tr><th>Sistema</th><th>Descrição</th><th>Ordem</th><th>Vínculos</th><th>Situação</th><th>Ações</th></tr></thead><tbody>
<?php if(!$categories): ?><tr><td colspan="6"><div class="table-empty"><i class="bi bi-grid"></i><strong>Nenhuma categoria encontrada</strong><span>Cadastre o primeiro sistema do veículo.</span></div></td></tr><?php endif; ?>
<?php foreach($categories as $category): ?><tr><td><div class="entity-cell"><?php if($category['imagem']): ?><img src="<?= url($category['imagem']) ?>" alt="Imagem de <?= e($category['nome']) ?>"><?php else: ?><span class="entity-placeholder"><i class="bi bi-<?= e($category['icone']?:'gear') ?>"></i></span><?php endif; ?><div><strong><?= e($category['nome']) ?></strong><small>Ícone: <?= e($category['icone']?:'gear') ?></small></div></div></td><td class="description-cell"><?= e($category['descricao']?:'Sem descrição') ?></td><td><?= (int)$category['ordem'] ?></td><td><strong><?= (int)$category['subcategorias'] ?> tópico(s)</strong><small><?= (int)$category['videos'] ?> vídeo(s)</small></td><td><span class="status <?= $category['ativo']?'active':'inactive' ?>"><?= $category['ativo']?'Ativa':'Inativa' ?></span></td><td><div class="row-actions"><?php if(can('categories','update')): ?><button class="action-btn" data-category-edit data-id="<?= (int)$category['id'] ?>" data-name="<?= e($category['nome']) ?>" data-description="<?= e($category['descricao']) ?>" data-icon="<?= e($category['icone']) ?>" data-order="<?= (int)$category['ordem'] ?>" data-active="<?= (int)$category['ativo'] ?>" data-image="<?= $category['imagem']?e(url($category['imagem'])):'' ?>" aria-label="Editar <?= e($category['nome']) ?>"><i class="bi bi-pencil"></i></button><?php endif; ?><?php if(can('categories','delete')): ?><button class="action-btn danger" data-category-delete data-id="<?= (int)$category['id'] ?>" data-name="<?= e($category['nome']) ?>" aria-label="Excluir <?= e($category['nome']) ?>"><i class="bi bi-trash"></i></button><?php endif; ?></div></td></tr><?php endforeach; ?>
</tbody></table></div>
<div class="pagination"><form method="get" action="<?= url('categorias') ?>" class="per-page"><input type="hidden" name="q" value="<?= e($q) ?>"><input type="hidden" name="status" value="<?= e($status) ?>"><label>Mostrar <select name="per_page" onchange="this.form.submit()"><?php foreach([5,10,25,50] as $size): ?><option value="<?= $size ?>" <?= $perPage===$size?'selected':'' ?>><?= $size ?></option><?php endforeach; ?></select> linhas</label></form><span>Mostrando <?= $totalRows?$offset+1:0 ?>–<?= min($offset+$perPage,$totalRows) ?> de <?= $totalRows ?></span><nav class="page-buttons" aria-label="Paginação"><?php if($page>1): ?><a href="<?= page_url('categorias',['page'=>$page-1]) ?>"><i class="bi bi-chevron-left"></i></a><?php endif; ?><?php for($p=max(1,$page-2);$p<=min($totalPages,$page+2);$p++): ?><a class="<?= $p===$page?'active':'' ?>" href="<?= page_url('categorias',['page'=>$p]) ?>"><?= $p ?></a><?php endfor; ?><?php if($page<$totalPages): ?><a href="<?= page_url('categorias',['page'=>$page+1]) ?>"><i class="bi bi-chevron-right"></i></a><?php endif; ?></nav></div>
</section>
<div class="modal" id="category-modal" aria-hidden="true"><div class="modal-dialog"><button class="modal-close" data-modal-close aria-label="Fechar"><i class="bi bi-x-lg"></i></button><div class="modal-content"><span class="eyebrow blue">Sistema do veículo</span><h2 data-category-modal-title>Nova categoria</h2><p>Use uma imagem clara ou um ícone do Bootstrap para identificar rapidamente o sistema.</p><form method="post" enctype="multipart/form-data" data-category-form><?= csrf_field() ?><input type="hidden" name="action" value="create"><input type="hidden" name="id"><div class="form-grid"><label>Nome da categoria<input name="nome" maxlength="120" required placeholder="Ex.: Botões no painel"></label><label>Ícone do Bootstrap<select name="icone"><option value="gear">Engrenagem</option><option value="gear-wide-connected">Motor</option><option value="fuel-pump">Combustível</option><option value="thermometer-half">Temperatura</option><option value="speedometer">Painel</option><option value="speedometer2">Velocímetro</option><option value="toggles">Botões</option><option value="controller">Volante</option><option value="shield-check">Segurança</option><option value="leaf">Condução econômica</option><option value="tools">Manutenção</option><option value="snow">Ar-condicionado</option><option value="wind">Exaustão</option><option value="truck-flatbed">Chassi</option><option value="sign-turn-right">Direção</option></select></label><label class="full">Descrição<textarea name="descricao" rows="4" maxlength="3000" placeholder="Explique o que este sistema abrange"></textarea></label><label>Ordem de exibição<input type="number" name="ordem" min="0" value="0"></label><label class="check"><input type="checkbox" name="ativo" checked> Categoria ativa</label><label class="full image-upload"><span class="image-preview" data-category-image-preview><i class="bi bi-image"></i></span><span><strong>Imagem da categoria</strong><small>JPG, PNG ou WEBP de até 5 MB</small><input type="file" name="imagem" accept="image/jpeg,image/png,image/webp" data-category-image-input></span></label></div><div class="modal-actions"><button type="button" class="btn secondary" data-modal-close>Cancelar</button><button class="btn primary"><i class="bi bi-check-lg"></i> Salvar categoria</button></div></form></div></div></div>
<div class="modal" id="delete-category-modal" aria-hidden="true"><div class="modal-dialog confirm-dialog"><button class="modal-close" data-modal-close aria-label="Fechar"><i class="bi bi-x-lg"></i></button><div class="modal-content"><span class="confirm-icon"><i class="bi bi-trash"></i></span><h2>Excluir categoria?</h2><p>Você está prestes a excluir <strong data-delete-category-name></strong>. Categorias com subcategorias ou vídeos vinculados não podem ser excluídas.</p><form method="post"><?= csrf_field() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" data-delete-category-id><div class="modal-actions"><button type="button" class="btn secondary" data-modal-close>Cancelar</button><button class="btn danger"><i class="bi bi-trash"></i> Excluir categoria</button></div></form></div></div></div>
